class LoadJobDetailUseCase(
    private val repository: JobRepository,
    private val savedRepository: SavedRepository,
    private val defaultDispatcher: CoroutineDispatcher
) {
    suspend operator fun invoke(id: String): JobDetailUi = coroutineScope {
        val detailDeferred = async { repository.getJob(id) }
        val savedDeferred = async { savedRepository.isSaved(id) }

        val detail = detailDeferred.await()
        val rendered = withContext(defaultDispatcher) {
            MarkdownParser.parse(detail.description)
        }

        JobDetailUi(detail, rendered, savedDeferred.await())
    }
}

class LegacyFileReader(
    private val ioDispatcher: CoroutineDispatcher
) {
    suspend fun read(path: String): String = withContext(ioDispatcher) {
        File(path).readText()
    }
}
